abstract class PricingStrategy {
    abstract Money calculateCharge(int quantity);

    Money calculateChargeWithMinimum(int quantity, Money minimumCharge) {
        Money calculated = calculateCharge(quantity);
        return calculated.isLessThan(minimumCharge) ? minimumCharge : calculated;
    }
}

class VolumePricingStrategy extends PricingStrategy {
    private final Money unitPrice;
    private final int volumeThreshold;
    private final double volumeDiscountRate;

    VolumePricingStrategy(Money unitPrice, int volumeThreshold, double volumeDiscountRate) {
        this.unitPrice = unitPrice;
        this.volumeThreshold = volumeThreshold;
        this.volumeDiscountRate = volumeDiscountRate;
    }

    public Money calculateCharge(int quantity) {
        Money baseCharge = unitPrice.multipliedBy(quantity);
        return quantity >= volumeThreshold
            ? baseCharge.multipliedBy(1 - volumeDiscountRate)
            : baseCharge;
    }
}
